	workspaceRoot := f.beadWorkspaceRoot()
	if workspaceRoot == "" {
		workspaceRoot = f.WorkingDir
	}
	beadsFile := ddxroot.JoinProject(workspaceRoot, "beads.jsonl")
	return f.beadAutoCommitPathsWithMode(operation, []string{beadsFile}, includeStaged)
